SELECT COUNT(*) AS total_sessions
FROM parking_sessions
WHERE user_id = 1;

SELECT license_plate
FROM parking_sessions
WHERE is_paid = 1;

SELECT bay_id
FROM parking_bays
WHERE lat = (SELECT MIN(lat) FROM parking_bays);

SELECT COUNT(session_id) AS active_paid_sessions
FROM parking_sessions
WHERE is_paid = 1;

SELECT user_id, COUNT(*) AS session_count
FROM parking_sessions
GROUP BY user_id;
